							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Create] aws_instance.example\n\n1 resource(s) to change\n",
		},
		"no-op changes are included": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.NoOp,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "",
		},
		"forget action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: makeAddr("aws_instance", "example"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Forget,
							},
							DeposedKey: states.NotDeposed,
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			expected: "[Forget] aws_instance.example\n\n1 resource(s) to change\n",
		},
	}

	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			formatter := &CompactDiffFormatter{}
			result := formatter.Format(tc.plan, tc.schemas)

			if result != tc.expected {
				t.Errorf("unexpected output\nGot:\n%q\n\nExpected:\n%q", result, tc.expected)
			}
		})
	}
}

func TestCompactDiffFormatter_Sorting(t *testing.T) {
	// Test that resources are sorted alphabetically within each action group
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: makeAddr("aws_instance", "zebra"),
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: makeAddr("aws_instance", "apple"),
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: makeAddr("aws_vpc", "main"),
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
					DeposedKey: states.NotDeposed,
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, &schemarepo.Schemas{})

	lines := strings.Split(strings.TrimSpace(result), "\n")
	// Should have 3 creates + blank line + summary = 5 lines
	if len(lines) != 5 {
		t.Errorf("expected 5 lines, got %d", len(lines))
	}

	// Check ordering
	if lines[0] != "[Create] aws_instance.apple" {
		t.Errorf("first line should be apple, got %q", lines[0])
	}
	if lines[1] != "[Create] aws_instance.zebra" {
		t.Errorf("second line should be zebra, got %q", lines[1])
	}
	if lines[2] != "[Create] aws_vpc.main" {
		t.Errorf("third line should be vpc.main, got %q", lines[2])
	}
}

// Helper function to create an absolute resource instance address
func makeAddr(resType, name string) addrs.AbsResourceInstance {
	return addrs.AbsResourceInstance{
		Module: addrs.ModuleInstance{},
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.ManagedResourceMode,
				Type: resType,
				Name: name,
			},
		},
	}
}

